-- Users table
DROP TABLE IF EXISTS messages;
DROP TABLE IF EXISTS sessions;
DROP TABLE IF EXISTS chat_rooms;
DROP TABLE IF EXISTS users;

CREATE TABLE users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT NOT NULL UNIQUE,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TRIGGER update_users_timestamp
AFTER UPDATE ON users
BEGIN
    UPDATE users SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
END;

-- Sessions/Auth tokens table
CREATE TABLE sessions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    token TEXT NOT NULL UNIQUE,
    expires_at TIMESTAMP NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

CREATE INDEX idx_sessions_token ON sessions(token);
CREATE INDEX idx_sessions_user_id ON sessions(user_id);
CREATE INDEX idx_sessions_expires ON sessions(expires_at);

-- Chat rooms table
CREATE TABLE chat_rooms (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE,
    description TEXT,
    created_by INTEGER NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE CASCADE
);

CREATE TRIGGER update_chat_rooms_timestamp
AFTER UPDATE ON chat_rooms
BEGIN
    UPDATE chat_rooms SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;
END;

-- Messages table (persisted)
CREATE TABLE messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    room_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    content TEXT NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (room_id) REFERENCES chat_rooms(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

CREATE INDEX idx_messages_room_id ON messages(room_id);
CREATE INDEX idx_messages_user_id ON messages(user_id);
CREATE INDEX idx_messages_created_at ON messages(created_at);

-- Room participants (for future room membership management)
CREATE TABLE room_participants (
    room_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    joined_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (room_id, user_id),
    FOREIGN KEY (room_id) REFERENCES chat_rooms(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

import hashlib
import secrets
from datetime import datetime, timedelta
from database import get_db


class User:
    def __init__(self, id, username, email, password_hash, created_at, updated_at):
        self.id = id
        self.username = username
        self.email = email
        self.password_hash = password_hash
        self.created_at = created_at
        self.updated_at = updated_at

    def to_dict(self):
        return {
            "id": self.id,
            "username": self.username,
            "email": self.email,
            "created_at": self.created_at.isoformat() if self.created_at else None,
            "updated_at": self.updated_at.isoformat() if self.updated_at else None,
        }

    @staticmethod
    def hash_password(password):
        return hashlib.sha256(password.encode()).hexdigest()

    @staticmethod
    def create(username, email, password):
        password_hash = User.hash_password(password)
        db = get_db()
        cursor = db.execute(
            "INSERT INTO users (username, email, password_hash) VALUES (?, ?, ?)",
            (username, email, password_hash),
        )
        db.commit()
        return User.get_by_id(cursor.lastrowid)

    @staticmethod
    def get_by_id(user_id):
        row = get_db().execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if row is None:
            return None
        return User(**dict(row))

    @staticmethod
    def get_by_username(username):
        row = get_db().execute("SELECT * FROM users WHERE username = ?", (username,)).fetchone()
        if row is None:
            return None
        return User(**dict(row))

    @staticmethod
    def get_by_email(email):
        row = get_db().execute("SELECT * FROM users WHERE email = ?", (email,)).fetchone()
        if row is None:
            return None
        return User(**dict(row))

    @staticmethod
    def verify_password(user, password):
        return user.password_hash == User.hash_password(password)


class Session:
    def __init__(self, id, user_id, token, expires_at, created_at):
        self.id = id
        self.user_id = user_id
        self.token = token
        self.expires_at = expires_at
        self.created_at = created_at

    def to_dict(self):
        return {
            "id": self.id,
            "user_id": self.user_id,
            "token": self.token,
            "expires_at": self.expires_at.isoformat() if self.expires_at else None,
            "created_at": self.created_at.isoformat() if self.created_at else None,
        }

    def is_expired(self):
        return datetime.now() > self.expires_at

    @staticmethod
    def create(user_id, expiration_hours=24):
        token = secrets.token_urlsafe(32)
        expires_at = datetime.now() + timedelta(hours=expiration_hours)
        db = get_db()
        cursor = db.execute(
            "INSERT INTO sessions (user_id, token, expires_at) VALUES (?, ?, ?)",
            (user_id, token, expires_at),
        )
        db.commit()
        return Session.get_by_id(cursor.lastrowid)

    @staticmethod
    def get_by_id(session_id):
        row = get_db().execute("SELECT * FROM sessions WHERE id = ?", (session_id,)).fetchone()
        if row is None:
            return None
        return Session(**dict(row))

    @staticmethod
    def get_by_token(token):
        row = get_db().execute("SELECT * FROM sessions WHERE token = ?", (token,)).fetchone()
        if row is None:
            return None
        session = Session(**dict(row))
        if session.is_expired():
            session.delete()
            return None
        return session

    @staticmethod
    def delete(token):
        db = get_db()
        db.execute("DELETE FROM sessions WHERE token = ?", (token,))
        db.commit()

    @staticmethod
    def delete_expired():
        db = get_db()
        db.execute("DELETE FROM sessions WHERE expires_at < ?", (datetime.now(),))
        db.commit()


class ChatRoom:
    def __init__(self, id, name, description, created_by, created_at, updated_at):
        self.id = id
        self.name = name
        self.description = description
        self.created_by = created_by
        self.created_at = created_at
        self.updated_at = updated_at

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "description": self.description,
            "created_by": self.created_by,
            "created_at": self.created_at.isoformat() if self.created_at else None,
            "updated_at": self.updated_at.isoformat() if self.updated_at else None,
        }

    @staticmethod
    def create(name, description, created_by):
        db = get_db()
        cursor = db.execute(
            "INSERT INTO chat_rooms (name, description, created_by) VALUES (?, ?, ?)",
            (name, description, created_by),
        )
        db.commit()
        return ChatRoom.get_by_id(cursor.lastrowid)

    @staticmethod
    def get_by_id(room_id):
        row = get_db().execute("SELECT * FROM chat_rooms WHERE id = ?", (room_id,)).fetchone()
        if row is None:
            return None
        return ChatRoom(**dict(row))

    @staticmethod
    def get_all():
        rows = get_db().execute("SELECT * FROM chat_rooms ORDER BY created_at DESC").fetchall()
        return [ChatRoom(**dict(row)) for row in rows]

    @staticmethod
    def delete(room_id):
        db = get_db()
        db.execute("DELETE FROM chat_rooms WHERE id = ?", (room_id,))
        db.commit()


class Message:
    def __init__(self, id, room_id, user_id, content, created_at):
        self.id = id
        self.room_id = room_id
        self.user_id = user_id
        self.content = content
        self.created_at = created_at

    def to_dict(self):
