            "id": self.id,
            "room_id": self.room_id,
            "user_id": self.user_id,
            "content": self.content,
            "created_at": self.created_at.isoformat() if self.created_at else None,
        }

    @staticmethod
    def create(room_id, user_id, content):
        db = get_db()
        cursor = db.execute(
            "INSERT INTO messages (room_id, user_id, content) VALUES (?, ?, ?)",
            (room_id, user_id, content),
        )
        db.commit()
        return Message.get_by_id(cursor.lastrowid)

    @staticmethod
    def get_by_id(message_id):
        row = get_db().execute("SELECT * FROM messages WHERE id = ?", (message_id,)).fetchone()
        if row is None:
            return None
        return Message(**dict(row))

    @staticmethod
    def get_by_room(room_id, limit=100, offset=0):
        rows = get_db().execute(
            "SELECT * FROM messages WHERE room_id = ? ORDER BY created_at DESC LIMIT ? OFFSET ?",
            (room_id, limit, offset),
        ).fetchall()
        return [Message(**dict(row)) for row in rows]

    @staticmethod
    def get_by_user(user_id, limit=50):
        rows = get_db().execute(
            "SELECT * FROM messages WHERE user_id = ? ORDER BY created_at DESC LIMIT ?",
            (user_id, limit),
        ).fetchall()
        return [Message(**dict(row)) for row in rows]

    @staticmethod
    def delete(message_id):
        db = get_db()
        db.execute("DELETE FROM messages WHERE id = ?", (message_id,))
        db.commit()

from flask import Blueprint, request, jsonify
from functools import wraps
import datetime

from models import User, Session
from database import get_db

bp = Blueprint("auth", __name__)


def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization")
        if not auth_header or not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid authorization header"}), 401

        token = auth_header.split(" ", 1)[1]
        session = Session.get_by_token(token)

        if not session:
            return jsonify({"error": "Invalid or expired token"}), 401

        request.user_id = session.user_id
        request.session = session
        return f(*args, **kwargs)

    return decorated


@bp.route("/register", methods=["POST"])
def register():
    data = request.get_json()

    if not data:
        return jsonify({"error": "No data provided"}), 400

    username = data.get("username")
    email = data.get("email")
    password = data.get("password")

    if not username or not email or not password:
        return jsonify({"error": "Username, email, and password are required"}), 400

    if len(password) < 6:
        return jsonify({"error": "Password must be at least 6 characters"}), 400

    db = get_db()
    existing_user = db.execute(
        "SELECT id FROM users WHERE username = ? OR email = ?", (username, email)
    ).fetchone()

    if existing_user:
        return jsonify({"error": "Username or email already exists"}), 409

    user = User.create(username, email, password)
    session = Session.create(user.id)

    return jsonify({
        "user": user.to_dict(),
        "token": session.token,
        "expires_at": session.expires_at.isoformat()
    }), 201


@bp.route("/login", methods=["POST"])
def login():
    data = request.get_json()

    if not data:
        return jsonify({"error": "No data provided"}), 400

    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"error": "Username and password are required"}), 400

    user = User.get_by_username(username)

    if not user or not User.verify_password(user, password):
        return jsonify({"error": "Invalid username or password"}), 401

    session = Session.create(user.id)

    return jsonify({
        "user": user.to_dict(),
        "token": session.token,
        "expires_at": session.expires_at.isoformat()
    })


@bp.route("/logout", methods=["POST"])
@require_auth
def logout():
    request.session.delete()
    return jsonify({"message": "Logged out successfully"})


@bp.route("/me", methods=["GET"])
@require_auth
def get_current_user():
    user = User.get_by_id(request.user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404
    return jsonify(user.to_dict())


@bp.route("/refresh", methods=["POST"])
@require_auth
def refresh_token():
    request.session.delete()
    new_session = Session.create(request.user_id)
    return jsonify({
        "token": new_session.token,
        "expires_at": new_session.expires_at.isoformat()
    })

