from flask import Blueprint, request, jsonify
from models import Message, ChatRoom, User
from routes.auth import require_auth

bp = Blueprint("messages", __name__)


@bp.route("/rooms/<int:room_id>/messages", methods=["GET"])
def get_messages(room_id):
    room = ChatRoom.get_by_id(room_id)
    if not room:
        return jsonify({"error": "Room not found"}), 404

    limit = request.args.get("limit", 100, type=int)
    offset = request.args.get("offset", 0, type=int)

    messages = Message.get_by_room(room_id, limit, offset)
    return jsonify([msg.to_dict() for msg in messages])


@bp.route("/rooms/<int:room_id>/messages", methods=["POST"])
@require_auth
def send_message(room_id):
    room = ChatRoom.get_by_id(room_id)
    if not room:
        return jsonify({"error": "Room not found"}), 404

    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400

    content = data.get("content")
    if not content or not content.strip():
        return jsonify({"error": "Message content is required"}), 400

    message = Message.create(room_id, request.user_id, content.strip())
    return jsonify(message.to_dict()), 201


@bp.route("/messages/<int:message_id>", methods=["DELETE"])
@require_auth
def delete_message(message_id):
    message = Message.get_by_id(message_id)
    if not message:
        return jsonify({"error": "Message not found"}), 404

    if message.user_id != request.user_id:
        return jsonify({"error": "You can only delete your own messages"}), 403

    Message.delete(message_id)
    return jsonify({"message": "Message deleted successfully"})


@bp.route("/users/<int:user_id>/messages", methods=["GET"])
@require_auth
def get_user_messages(user_id):
    if user_id != request.user_id:
        return jsonify({"error": "Unauthorized"}), 403

    limit = request.args.get("limit", 50, type=int)
    messages = Message.get_by_user(user_id, limit)
    return jsonify([msg.to_dict() for msg in messages])
